using System.Reflection;

var absAsm = Assembly.Load("Microsoft.Agents.AI.Abstractions");

void DumpType(Type t) {
    Console.WriteLine($"\n=== {t.FullName} (base: {t.BaseType?.Name}) ===");
    foreach (var p in t.GetProperties(BindingFlags.Public|BindingFlags.Instance|BindingFlags.DeclaredOnly))
        Console.WriteLine($"  P: {p.PropertyType.Name} {p.Name} {(p.CanWrite?"[rw]":"[r]")}");
    foreach (var m in t.GetMethods(BindingFlags.Public|BindingFlags.Instance|BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  M: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name))})");
    foreach (var c in t.GetConstructors()) {
        var pars = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  ctor({pars})");
    }
}

var names = new[] {
    "Microsoft.Agents.AI.AgentResponse",
    "Microsoft.Agents.AI.AgentResponseUpdate",
    "Microsoft.Agents.AI.AgentRunOptions",
    "Microsoft.Agents.AI.AgentSession",
    "Microsoft.Agents.AI.AIAgent",
};
foreach (var name in names) {
    var t = absAsm.GetType(name);
    if (t != null) DumpType(t);
    else Console.WriteLine($"NOT FOUND: {name}");
}
