namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities by querying DuckDuckGo and returning
/// parsed results. Each search returns a list of titles, snippets, and URLs.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Searches the web for the given query and returns a list of results with titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var results = ParseSearchResults(html);

            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            return $"Search results for \"{query}\":\n\n" +
                   string.Join("\n\n", results.Select((r, i) =>
                       $"[{i + 1}] {r.Title}\n    {r.Snippet}\n    URL: {r.Url}"));
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();

        var linkMatches = ResultLinkRegex().Matches(html);
        var snippetMatches = SnippetRegex().Matches(html);

        var count = Math.Min(linkMatches.Count, 5);
