using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent.
/// Notes are stored in memory and can be retrieved for summarization.
/// </summary>
public sealed class NotesTool
{
    private readonly List<NoteEntry> _notes = [];

    [Description("Adds a research note with a category and content. Use this to record key findings during research.")]
    public string AddNote(
        [Description("The category or topic area for this note (e.g., 'History', 'Statistics', 'Key People')")] string category,
        [Description("The content of the note capturing the key finding")] string content)
    {
        var entry = new NoteEntry(category, content, DateTime.UtcNow);
        _notes.Add(entry);
        return $"Note #{_notes.Count} added under \"{category}\".";
    }

    [Description("Retrieves all research notes collected so far, organized by category.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var grouped = _notes
            .GroupBy(n => n.Category, StringComparer.OrdinalIgnoreCase)
            .OrderBy(g => g.Key);

        var sections = grouped.Select(g =>
            $"## {g.Key}\n" +
            string.Join("\n", g.Select((n, i) => $"  {i + 1}. {n.Content}")));

        return $"Research Notes ({_notes.Count} total):\n\n" + string.Join("\n\n", sections);
    }

    /// <summary>Returns the raw note entries for display after the agent completes.</summary>
    public IReadOnlyList<NoteEntry> GetNotes() => _notes.AsReadOnly();

    public sealed record NoteEntry(string Category, string Content, DateTime Timestamp);
}

