using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tools ---
var notesTool = new NotesTool();
var webSearch = new WebSearchTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notesTool.AddNote),
    AIFunctionFactory.Create(notesTool.GetAllNotes),
];

// --- Create the ChatClientAgent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic:
        1. Search the web for multiple aspects of the topic (at least 3 different searches).
        2. As you find important information, add notes with appropriate categories.
        3. After gathering enough information, retrieve all notes and provide a
           well-structured summary covering the key findings.

        Be systematic: start broad, then dive into specific sub-topics.
        Always cite sources when possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web, taking notes, and summarizing findings",
    tools: tools);

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly. Search for multiple aspects, " +
    $"take notes on key findings, then provide a comprehensive summary.\n\nTopic: {topic}",
    session,
    runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();

// --- Display collected notes ---
var notes = notesTool.GetNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n══════════════════════════════════════");
    Console.WriteLine($"  Research Notes ({notes.Count} collected)");
    Console.WriteLine("══════════════════════════════════════");

    var grouped = notes
        .GroupBy(n => n.Category, StringComparer.OrdinalIgnoreCase)
        .OrderBy(g => g.Key);

    foreach (var group in grouped)
    {
        Console.WriteLine($"\n  [{group.Key}]");
        foreach (var note in group)
        {
            Console.WriteLine($"    • {note.Content}");
        }
    }

    Console.WriteLine();
}

